[
  {
    "file": "internal/terraform/evaluate.go",
    "line": 247,
    "severity": "critical",
    "description": "Inverted condition for undeclared variable check. The code checks 'if config != nil' but the error message says 'Reference to undeclared input variable'. This should be 'if config == nil'. Currently, the error is shown when the variable IS declared (config != nil), instead of when it's NOT declared. This causes the function to report false errors for declared variables and fail to report real errors for undeclared ones.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -244,7 +244,7 @@ func (d *evaluationStateData) GetInputVariable(addr addrs.InputVariable, rng tfd
 	}

 	config := moduleConfig.Module.Variables[addr.Name]
-	if config != nil {
+	if config == nil {
 		var suggestions []string
 		for k := range moduleConfig.Module.Variables {
 			suggestions = append(suggestions, k)
"
  },
  {
    "file": "internal/terraform/evaluate.go",
    "line": 281,
    "severity": "critical",
    "description": "Inverted condition for validate walk check. The code checks 'if d.Operation != walkValidate' before returning unknown values, but the comment explicitly states 'During the validate walk, input variables are always unknown'. This is backwards: during validate walk, the function should return unknown values; during other walks (plan, apply), it should return actual values. Currently it does the opposite, causing validation to use known values and planning to use unknown values.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -278,7 +278,7 @@ func (d *evaluationStateData) GetInputVariable(addr addrs.InputVariable, rng tfd
 	// that are disabled, etc. Terraform's static validation leans towards
 	// being liberal in what it accepts because the subsequent plan walk has
 	// more information available and so can be more conservative.
-	if d.Operation != walkValidate {
+	if d.Operation == walkValidate {
 		// We should still capture the statically-configured marks during
 		// the validate walk.
 		ret := cty.UnknownVal(config.Type)
"
  },
  {
    "file": "internal/terraform/evaluate.go",
    "line": 535,
    "severity": "critical",
    "description": "Inverted condition for unknown instance keys check. The code checks '!hasUnknownKeys' but the logic immediately following says 'because it means we have an unknown for_each/count'. The condition is backwards: when hasUnknownKeys is TRUE (we have unknown keys), we should return DynamicVal; currently it returns DynamicVal when hasUnknownKeys is FALSE. This breaks deferred resource handling during planning.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -532,7 +532,7 @@ func (d *evaluationStateData) GetResource(addr addrs.Resource, rng tfdiags.Sourc
 	// result for _all_ of its work, rather than continuing to duplicate a bunch
 	// of the logic we've tried to encapsulate over ther already.
 	if d.Operation == walkPlan || d.Operation == walkApply {
-		if _, _, hasUnknownKeys := d.Evaluator.Instances.ResourceInstanceKeys(addr.Absolute(moduleAddr)); !hasUnknownKeys {
+		if _, _, hasUnknownKeys := d.Evaluator.Instances.ResourceInstanceKeys(addr.Absolute(moduleAddr)); hasUnknownKeys {
 			// There really isn't anything interesting we can do in this situation,
 			// because it means we have an unknown for_each/count, in which case
 			// we can't even predict what the result type will be because it
"
  },
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 192,
    "severity": "critical",
    "description": "Inverted condition for ephemeral variable marking. The code checks 'if !cfg.Ephemeral' (NOT ephemeral) before marking the value as ephemeral. The comment states 'An ephemeral input variable always has an ephemeral value inside the module', which means when cfg.Ephemeral IS TRUE, the value should be marked as ephemeral. Currently, non-ephemeral variables get marked as ephemeral, and ephemeral variables don't. This completely inverts the ephemeral marking logic.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -189,7 +189,7 @@ func prepareFinalInputVariableValue(addr addrs.AbsInputVariableInstance, raw *In
 		}
 	}

-	if !cfg.Ephemeral {
+	if cfg.Ephemeral {
 		// An ephemeral input variable always has an ephemeral value inside the
 		// module, even if the value assigned to it from outside is not. This
 		// is a useful simplification so that module authors can be explicit
"
  },
  {
    "file": "internal/terraform/hook.go",
    "line": 138,
    "severity": "critical",
    "description": "Wrong return value in NilHook.PreApply(). The NilHook is designed as a no-op hook that all custom hooks embed and override selectively. PreApply returns HookActionHalt instead of HookActionContinue, unlike all other NilHook methods. This causes any hook that embeds NilHook and doesn't override PreApply to halt all apply operations. This is a critical cross-component bug that breaks the entire apply workflow.",
    "fix_patch": "--- a/internal/terraform/hook.go
+++ b/internal/terraform/hook.go
@@ -135,7 +135,7 @@ type NilHook struct{}
 var _ Hook = (*NilHook)(nil)

 func (*NilHook) PreApply(id HookResourceIdentity, dk addrs.DeposedKey, action plans.Action, priorState, plannedNewState cty.Value) (HookAction, error) {
-	return HookActionHalt, nil
+	return HookActionContinue, nil
 }

 func (*NilHook) PostApply(id HookResourceIdentity, dk addrs.DeposedKey, newState cty.Value, err error) (HookAction, error) {
"
  },
  {
    "file": "internal/terraform/context_apply.go",
    "line": 147,
    "severity": "medium",
    "description": "Hook return values not checked in import notification loop. The code calls h.PreApplyImport() and h.PostApplyImport() but ignores their return values. The Hook interface specifies that these methods return (HookAction, error), which allows hooks to halt processing by returning HookActionHalt. Not checking these values is inconsistent with the Hook interface design and prevents hooks from controlling the import operation flow, even though import is currently a no-op.",
    "fix_patch": "--- a/internal/terraform/context_apply.go
+++ b/internal/terraform/context_apply.go
@@ -144,8 +144,16 @@ func (c *Context) ApplyAndEval(plan *plans.Plan, config *configs.Config, opts *
 		for _, h := range c.hooks {
 			// In future, we may need to call PostApplyImport separately elsewhere in the apply
 			// operation. For now, though, we'll call Pre and Post hooks together.
-			h.PreApplyImport(hookResourceID, *rc.Importing)
-			h.PostApplyImport(hookResourceID, *rc.Importing)
+			action, _ := h.PreApplyImport(hookResourceID, *rc.Importing)
+			if action == HookActionHalt {
+				break
+			}
+			action, _ = h.PostApplyImport(hookResourceID, *rc.Importing)
+			if action == HookActionHalt {
+				break
+			}
 		}
 	}
 }
"
  }
]

